export type MetricsType = 'counter' | 'timer' | 'store' | 'rate_counter' | 'meter';
export interface MetricsOptionsType {
    debug: boolean;
    silentVerifying: boolean;
    host: string;
    port: number;
    defaultPrefix: string;
    bufferSize: number;
    flushInterval: number;
    /**
     * deprecated
     */
    unixDgram?: boolean;
    logger?: ILogger;
    /**
     * 开启了预聚合需要提前预定义 tag key
     */
    enablePreAggregate?: boolean;
    /**
     * 是否禁用内置的 cluster tag，默认为 false
     */
    disableBuiltinClusterTag?: boolean;
}
export interface ILogger {
    fatal(message: string, ...splat: any[]): void;
    error(message: string, ...splat: any[]): void;
    warn(message: string, ...splat: any[]): void;
    info(message: string, ...splat: any[]): void;
    debug(message: string, ...splat: any[]): void;
    trace(message: string, ...splat: any[]): void;
}
export interface PreDefineTagKeyOptionsType {
    name: string;
    prefix?: string;
    metricType: MetricsType;
    keys: string[];
}
